nslateX(-50%) translateY(-5px)}}.company-section{padding:100px 0;background:transparent}.services-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(300px,1fr));gap:30px;margin-top:50px}.service-card{background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.1);padding:40px 30px;border-radius:15px;transition:var(--transition)}.service-card:hover{background:rgba(29,79,145,0.2);border-color:var(--primary);transform:translateY(-10px)}.service-icon{width:60px;height:60px;background:var(--primary);border-radius:12px;display:flex;align-items:center;justify-content:center;margin-bottom:25px;color:var(--white)}.service-card h3{color:var(--white);font-size:1.4rem;margin-bottom:15px}.service-card p{color:var(--gray);line-height:1.7}.about-company-wrapper{display:grid;grid-template-columns:1fr 1fr;gap:60px;align-items:center}.about-company-image{position:relative;border-radius:15px;overflow:hidden}.about-company-image img{width:100%;height:auto;display:block}.about-company-content h2{font-family:var(--font-display);font-size:2.5rem;color:var(--white);margin-bottom:25px}.about-company-content p{color:var(--gray);line-height:1.8;margin-bottom:20px}.contact-company{background:rgba(29,79,145,0.1);border-radius:20px;padding:50px;margin-top:50px}.contact-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(250px,1fr));gap:30px}.contact-item{display:flex;align-items:flex-start;gap:15px}.contact-item-icon{width:50px;height:50px;background:var(--primary);border-radius:10px;display:flex;align-items:center;justify-content:center;color:var(--white);flex-shrink:0}.contact-item h4{color:var(--white);margin-bottom:5px}.contact-item p{color:var(--gray)}.back-link{display:inline-flex;align-items:center;gap:10px;color:var(--accent);text-decoration:none;font-weight:600;margin-bottom:30px;transition:var(--transition)}.back-link:hover{color:var(--white)}@media(max-width: 900px){.about-company-wrapper{grid-template-columns:1fr}.layer-2,.layer-3{clip-path:none}}
